use crate::mal_prelude::*;
use bun_alloc::ArenaVecExt as _;
use core::mem::offset_of;
use core::sync::atomic::AtomicUsize;

use bun_alloc::Arena; // bumpalo::Bump re-export
use bun_collections::{ArrayHashMap, AutoBitSet, VecExt};
use bun_core::strings;
use bun_paths::{PathBuffer, resolve_path};
use bun_sourcemap::SourceMapPieces;
use bun_wyhash::{self, Wyhash};

use crate::bun_css;
use crate::bun_fs;
use crate::options::{PathTemplate, PlaceholderField};
use crate::{BundleV2, Chunk, Index, IndexInt, LinkerContext};

// Typed SoA column accessors generated by ``.
use super::find_all_imported_parts_in_js_order::find_all_imported_parts_in_js_order;
use super::find_imported_css_files_in_js_order::find_imported_css_files_in_js_order;
use super::find_imported_files_in_css_order::find_imported_files_in_css_order;

#[inline(always)]
fn make_flags(has_html_chunk: bool, is_browser_chunk_from_server_build: bool) -> chunk::Flags {
    let mut f = chunk::Flags::empty();
    if has_html_chunk {
        f |= chunk::Flags::HAS_HTML_CHUNK;
    }
    if is_browser_chunk_from_server_build {
        f |= chunk::Flags::IS_BROWSER_CHUNK_FROM_SERVER_BUILD;
    }
    f
}

// TODO(port): narrow error set
#[inline(never)]
pub fn compute_chunks(
    this: &mut LinkerContext,
    unique_key: u64,
) -> Result<Box<[Chunk]>, bun_core::Error> {
    let _trace = bun_core::perf::trace("Bundler.computeChunks");

    debug_assert!(this.dev_server.is_none()); // use

    // PERF(port): was stack-fallback (std.heap.stackFallback(4096, ...)) — profile in Phase B
    // PERF(port): was arena bulk-free — temp allocations freed at end of fn
    let arena = Arena::new();
    let temp = &arena;

    // TODO(port): StringArrayHashMap keyed by arena-allocated &[u8]; using ArrayHashMap<&[u8], Chunk> here.
    let mut js_chunks: ArrayHashMap<&[u8], Chunk> = ArrayHashMap::new();
    js_chunks.reserve(this.graph.entry_points.len());

    // Key is the hash of the CSS order. This deduplicates identical CSS files.
    let mut css_chunks: ArrayHashMap<u64, Chunk> = ArrayHashMap::new();
    let mut js_chunks_with_css: usize = 0;

    // Maps entry point IDs to their index in js_chunks.values().
    // CSS-only entry points that skip JS chunk creation get maxInt as sentinel.
    let entry_point_to_js_chunk_idx: &mut [u32] =
        temp.alloc_slice_fill_copy(this.graph.entry_points.len(), u32::MAX);

    // SAFETY: `parse_graph` is a backref into `BundleV2.graph`, valid for the
    // link step. Raw deref (not `this.parse_graph()`) because the loop below
    // needs disjoint `&mut this.graph.*` borrows while `parse_graph` is held.
    let parse_graph = unsafe { &*this.parse_graph };
    // `bump` is a `BackRef` into `BundleV2.graph.arena`, valid for the link step.
    // Hoisted so the loop can hold disjoint &mut borrows into `this.graph`.
    // PORT NOTE: `BundlerStyleSheet::empty()` no longer takes an arena in Rust; kept for
    // Phase B when arena threading lands.
    let _arena: &Arena = this.graph.arena();

    // PORT NOTE: borrowck escape hatch — the SoA column slices below hold disjoint
    // immutable borrows into `this.graph` while several helpers (and the BundleV2
    // back-pointer recovery) still want `&mut LinkerContext`. The Zig original
    // freely aliases; Phase B should thread split borrows through `LinkerGraph`
    // instead of laundering through a raw pointer.
    let this_ptr: *mut LinkerContext = this;

    let entry_source_indices = this.graph.entry_points.items_source_index();
    let css_asts = this.graph.ast.items_css();
    let mut html_chunks: ArrayHashMap<&[u8], Chunk> = ArrayHashMap::new();
    let loaders = parse_graph.input_files.items_loader();
    let ast_targets = this.graph.ast.items_target();

    let code_splitting = this.graph.code_splitting;
    let could_be_browser_target_from_server_build = this.options.target.is_server_side()
        && parse_graph.html_imports.html_source_indices.len() > 0;
    let has_server_html_imports = parse_graph.html_imports.server_source_indices.len() > 0;

    // Create chunks for entry points
    for (entry_id_, &source_index) in entry_source_indices.iter().enumerate() {
        let entry_bit = entry_id_ as chunk::EntryPointId; // @truncate

        // PORT NOTE: reshaped for borrowck — set the bit through a scoped &mut, then keep an
        // owned clone so the `this.graph.files` borrow does not span the helper calls below
        // that need `&LinkerContext` / `&mut LinkerContext`.
        let entry_bits: AutoBitSet = {
            let eb = &mut this.graph.files.items_entry_bits_mut()[source_index as usize];
            eb.set(entry_bit as usize);
            eb.clone()?
        };

        let has_html_chunk = loaders[source_index as usize] == Loader::Html;

        // For code splitting, entry point chunks should be keyed by ONLY the entry point's
        // own bit, not the full entry_bits. This ensures that if an entry point file is
        // reachable from other entry points (e.g., via re-exports), its content goes into
        // a shared chunk rather than staying in the entry point's chunk.
        // https://github.com/evanw/esbuild/blob/cd832972927f1f67b6d2cc895c06a8759c1cf309/internal/linker/linker.go#L3882
        let mut entry_point_chunk_bits = AutoBitSet::init_empty(this.graph.entry_points.len())?;
        entry_point_chunk_bits.set(entry_bit as usize);

        let js_chunk_key: &[u8] = 'brk: {
            if code_splitting {
                break 'brk temp
                    .alloc_slice_copy(entry_point_chunk_bits.bytes(this.graph.entry_points.len()));
            } else {
                // Force HTML chunks to always be generated, even if there's an identical JS file.
                // PORT NOTE: Zig used a Formatter struct; build the byte key directly since
                // entry_bits is arbitrary bytes (not UTF-8) and cannot go through fmt::Display.
                let mut v = bun_alloc::ArenaVec::new_in(temp);
                v.push((!has_html_chunk) as u8);
                v.extend_from_slice(entry_bits.bytes(this.graph.entry_points.len()));
                break 'brk v.into_bump_slice();
            }
        };

        // Put this early on in this loop so that CSS-only entry points work.
        if has_html_chunk {
            let html_chunk_entry = html_chunks.get_or_put(js_chunk_key)?;
            if !html_chunk_entry.found_existing {
                *html_chunk_entry.value_ptr = Chunk {
                    entry_point: chunk::EntryPoint::new(source_index, entry_bit, true, false),
                    entry_bits: entry_point_chunk_bits.clone()?,
                    content: chunk::Content::Html,
                    output_source_map: SourceMapPieces::init(),
                    flags: make_flags(
                        false,
                        could_be_browser_target_from_server_build
                            && ast_targets[source_index as usize] == Target::Browser,
                    ),
                    ..Default::default()
                };
            }
        }

        if css_asts[source_index as usize].is_some() {
            // SAFETY: see `this_ptr` PORT NOTE above — the helper only reads from
            // `this.graph` columns disjoint from the slices we hold here.
            let order = find_imported_files_in_css_order(
                unsafe { &mut *this_ptr },
                temp,
                &[Index::init(source_index)],
            );
            // Create a chunk for the entry point here to ensure that the chunk is
            // always generated even if the resulting file is empty
            let hash_to_use = if !this.options.css_chunking {
                bun_wyhash::hash(
                    temp.alloc_slice_copy(entry_bits.bytes(this.graph.entry_points.len())),
                )
            } else {
                let mut hasher = Wyhash::init(5);
                bun_core::write_any_to_hasher(&mut hasher, order.len());
                for x in order.slice() {
                    x.hash(&mut hasher);
                }
                hasher.final_()
            };
            let css_chunk_entry = css_chunks.get_or_put(hash_to_use)?;
            if !css_chunk_entry.found_existing {
                // const css_chunk_entry = try js_chunks.getOrPut();
                let order_len = order.len() as usize;
                *css_chunk_entry.value_ptr = Chunk {
                    entry_point: chunk::EntryPoint::new(source_index, entry_bit, true, false),
                    entry_bits: entry_point_chunk_bits,
                    content: chunk::Content::Css(chunk::CssChunk {
                        imports_in_chunk_in_order: order,
                        asts: (0..order_len)
                            .map(|_| bun_css::BundlerStyleSheet::empty())
                            .collect::<Vec<_>>()
                            .into_boxed_slice(),
                    }),
                    output_source_map: SourceMapPieces::init(),
                    flags: make_flags(
                        has_html_chunk,
                        could_be_browser_target_from_server_build
                            && ast_targets[source_index as usize] == Target::Browser,
                    ),
                    ..Default::default()
                };
            }

            continue;
        }

        // Create a chunk for the entry point here to ensure that the chunk is
        // always generated even if the resulting file is empty
        let js_chunk_entry = js_chunks.get_or_put(js_chunk_key)?;
        entry_point_to_js_chunk_idx[entry_id_] =
            u32::try_from(js_chunk_entry.index).expect("int cast");
        *js_chunk_entry.value_ptr = Chunk {
            entry_point: chunk::EntryPoint::new(source_index, entry_bit, true, false),
            entry_bits: entry_point_chunk_bits,
            content: chunk::Content::Javascript(chunk::JavaScriptChunk::default()),
            output_source_map: SourceMapPieces::init(),
            flags: make_flags(
                has_html_chunk,
                could_be_browser_target_from_server_build
                    && ast_targets[source_index as usize] == Target::Browser,
            ),
            ..Default::default()
        };

        {
            // If this JS entry point has an associated CSS entry point, generate it
            // now. This is essentially done by generating a virtual CSS file that
            // only contains "@import" statements in the order that the files were
            // discovered in JS source order, where JS source order is arbitrary but
            // consistent for dynamic imports. Then we run the CSS import order
            // algorithm to determine the final CSS file order for the chunk.
            let css_source_indices =
                find_imported_css_files_in_js_order(this, temp, Index::init(source_index));
            if css_source_indices.len() > 0 {
                // SAFETY: see `this_ptr` PORT NOTE above.
                let order = find_imported_files_in_css_order(
                    unsafe { &mut *this_ptr },
                    temp,
                    css_source_indices.slice(),
                );

                // Always use content-based hashing for CSS chunk deduplication.
                // This ensures that when multiple JS entry points import the
                // same CSS files, they share a single CSS output chunk rather
                // than producing duplicates that collide on hash-based naming.
                let hash_to_use = {
                    let mut hasher = Wyhash::init(5);
                    bun_core::write_any_to_hasher(&mut hasher, order.len());
                    for x in order.slice() {
                        x.hash(&mut hasher);
                    }
                    hasher.final_()
                };

                let css_chunk_entry = css_chunks.get_or_put(hash_to_use)?;

                if let chunk::Content::Javascript(js) = &mut js_chunk_entry.value_ptr.content {
                    js.css_chunks = Box::<[u32]>::from(
                        &[u32::try_from(css_chunk_entry.index).expect("int cast")][..],
                    );
                }
                js_chunks_with_css += 1;

                if !css_chunk_entry.found_existing {
                    let order_len = order.len() as usize;
                    let mut css_files_with_parts_in_chunk: ArrayHashMap<IndexInt, AtomicUsize> =
                        ArrayHashMap::new();
                    for entry in order.slice() {
                        if let chunk::CssImportOrderKind::SourceIndex(si) = &entry.kind {
                            css_files_with_parts_in_chunk
                                .put(si.get(), AtomicUsize::new(0))
                                .expect("oom");
                        }
                    }
                    *css_chunk_entry.value_ptr = Chunk {
                        entry_point: chunk::EntryPoint::new(source_index, entry_bit, true, false),
                        entry_bits: entry_bits.clone()?,
                        content: chunk::Content::Css(chunk::CssChunk {
                            imports_in_chunk_in_order: order,
                            asts: (0..order_len)
                                .map(|_| bun_css::BundlerStyleSheet::empty())
                                .collect::<Vec<_>>()
                                .into_boxed_slice(),
                        }),
                        files_with_parts_in_chunk: css_files_with_parts_in_chunk,
                        output_source_map: SourceMapPieces::init(),
                        flags: make_flags(
                            has_html_chunk,
                            could_be_browser_target_from_server_build
                                && ast_targets[source_index as usize] == Target::Browser,
                        ),
                        ..Default::default()
                    };
                }
            }
        }
    }
    // PORT NOTE: reshaped for borrowck — re-borrow file_entry_bits after the loop above mutated it
    let file_entry_bits: &mut [AutoBitSet] = this.graph.files.items_entry_bits_mut();

    let css_reprs = this.graph.ast.items_css();

    // Figure out which JS files are in which chunk
    if js_chunks.count() > 0 {
        for source_index in this.graph.reachable_files.slice() {
            if this.graph.files_live.is_set(source_index.get() as usize) {
                if css_reprs[source_index.get() as usize].is_none() {
                    let entry_bits: &AutoBitSet = &file_entry_bits[source_index.get() as usize];
                    if css_reprs[source_index.get() as usize].is_some() {
                        continue;
                    }

                    if this.graph.code_splitting {
                        let js_chunk_key =
                            temp.alloc_slice_copy(entry_bits.bytes(this.graph.entry_points.len()));
                        let js_chunk_entry = js_chunks.get_or_put(js_chunk_key)?;

                        if !js_chunk_entry.found_existing {
                            let is_browser_chunk_from_server_build =
                                could_be_browser_target_from_server_build
                                    && ast_targets[source_index.get() as usize] == Target::Browser;
                            *js_chunk_entry.value_ptr = Chunk {
                                entry_bits: entry_bits.clone()?,
                                entry_point: chunk::EntryPoint::new(
                                    source_index.get(),
                                    0,
                                    false,
                                    false,
                                ),
                                content: chunk::Content::Javascript(
                                    chunk::JavaScriptChunk::default(),
                                ),
                                output_source_map: SourceMapPieces::init(),
                                flags: make_flags(false, is_browser_chunk_from_server_build),
                                ..Default::default()
                            };
                        } else if could_be_browser_target_from_server_build
                            && !js_chunk_entry.value_ptr.entry_point.is_entry_point()
                            && !js_chunk_entry
                                .value_ptr
                                .flags
                                .contains(chunk::Flags::IS_BROWSER_CHUNK_FROM_SERVER_BUILD)
                            && ast_targets[source_index.get() as usize] == Target::Browser
                        {
                            // If any file in the chunk has browser target, mark the whole chunk as browser.
                            // This handles the case where a lazy-loaded chunk (code splitting chunk, not entry point)
                            // contains browser-targeted files but was first created by a non-browser file.
                            // We only apply this to non-entry-point chunks to preserve the correct side for server entry points.
                            js_chunk_entry
                                .value_ptr
                                .flags
                                .insert(chunk::Flags::IS_BROWSER_CHUNK_FROM_SERVER_BUILD);
                        }

                        let entry = js_chunk_entry
                            .value_ptr
                            .files_with_parts_in_chunk
                            .get_or_put(source_index.get() as u32)
                            .expect("unreachable");
                        if !entry.found_existing {
                            *entry.value_ptr = AtomicUsize::new(0); // Initialize byte count to 0
                        }
                    } else {
                        // PORT NOTE: Zig used a local `Handler` struct passed to entry_bits.forEach;
                        // in Rust we pass a context struct + fn pointer.
                        struct Handler<'a> {
                            chunks: &'a mut [Chunk],
                            source_id: u32,
                            entry_point_to_js_chunk_idx: &'a [u32],
                        }
                        fn next(c: &mut Handler<'_>, entry_point_id: usize) {
                            // Map the entry point ID to the actual JS chunk index.
                            // CSS-only entry points don't have JS chunks (sentinel value).
                            let chunk_idx = c.entry_point_to_js_chunk_idx[entry_point_id];
                            if chunk_idx == u32::MAX {
                                return;
                            }

                            let entry = c.chunks[chunk_idx as usize]
                                .files_with_parts_in_chunk
                                .get_or_put(c.source_id as u32)
                                .expect("unreachable");
                            if !entry.found_existing {
                                *entry.value_ptr = AtomicUsize::new(0); // Initialize byte count to 0
                            }
                        }
                        let mut handler = Handler {
                            chunks: js_chunks.values_mut(),
                            source_id: source_index.get(),
                            entry_point_to_js_chunk_idx: &*entry_point_to_js_chunk_idx,
                        };
                        entry_bits.for_each(&mut handler, next);
                    }
                }
            }
        }
    }

    // Sort the chunks for determinism. This matters because we use chunk indices
    // as sorting keys in a few places.
    let mut sorted_chunks: Vec<Chunk> = 'sort_chunks: {
        let mut sorted_chunks = Vec::<Chunk>::init_capacity(
            js_chunks.count() + css_chunks.count() + html_chunks.count(),
        );

        let mut sorted_keys = Vec::<&[u8]>::init_capacity(js_chunks.count());

        // PERF(port): was assume_capacity
        sorted_keys.append_slice_assume_capacity(js_chunks.keys());

        // sort by entry_point_id to ensure the main entry point (id=0) comes first,
        // then by key for determinism among the rest.
        struct ChunkSortContext<'a> {
            chunks: &'a ArrayHashMap<&'a [u8], Chunk>,
        }

        impl<'a> ChunkSortContext<'a> {
            fn less_than(&self, a_key: &[u8], b_key: &[u8]) -> bool {
                let Some(a_chunk) = self.chunks.get(&a_key) else {
                    return true;
                };
                let Some(b_chunk) = self.chunks.get(&b_key) else {
                    return false;
                };
                let a_id = a_chunk.entry_point.entry_point_id();
                let b_id = b_chunk.entry_point.entry_point_id();

                // Main entry point (id=0) always comes first
                if a_id == 0 && b_id != 0 {
                    return true;
                }
                if b_id == 0 && a_id != 0 {
                    return false;
                }

                // Otherwise sort alphabetically by key for determinism
                strings::order(a_key, b_key) == core::cmp::Ordering::Less
            }
        }

        let ctx = ChunkSortContext { chunks: &js_chunks };
        sorted_keys.sort_by(|a, b| {
            if ctx.less_than(a, b) {
                core::cmp::Ordering::Less
            } else if ctx.less_than(b, a) {
                core::cmp::Ordering::Greater
            } else {
                core::cmp::Ordering::Equal
            }
        });
        let mut js_chunk_indices_with_css = Vec::<u32>::init_capacity(js_chunks_with_css);
        for &key in sorted_keys.slice() {
            let chunk = js_chunks.get(&key).expect("unreachable");

            if let chunk::Content::Javascript(js) = &chunk.content {
                if js.css_chunks.len() > 0 {
                    // PERF(port): was assume_capacity
                    js_chunk_indices_with_css.append_assume_capacity(sorted_chunks.len() as u32);
                }
            }

            // PERF(port): was assume_capacity
            // PORT NOTE: `Chunk` is not `Clone` (Zig is move-by-value); take by index.
            let idx = js_chunks.get_index(&key).expect("unreachable");
            let owned = core::mem::take(&mut js_chunks.values_mut()[idx]);
            let has_html = owned.flags.contains(chunk::Flags::HAS_HTML_CHUNK);
            sorted_chunks.append_assume_capacity(owned);

            // Attempt to order the JS HTML chunk immediately after the non-html one.
            if has_html {
                if let Some(html_idx) = html_chunks.get_index(&key) {
                    let (_, html_chunk) = html_chunks.swap_remove_at(html_idx);
                    // PERF(port): was assume_capacity
                    sorted_chunks.append_assume_capacity(html_chunk);
                }
            }
        }

        if css_chunks.count() > 0 {
            let sorted_css_keys: &mut [u64] = temp.alloc_slice_copy(css_chunks.keys());
            sorted_css_keys.sort_unstable();

            // A map from the index in `css_chunks` to it's final index in `sorted_chunks`
            let remapped_css_indexes: &mut [u32] =
                temp.alloc_slice_fill_copy(css_chunks.count(), 0u32);

            // Use sorted_chunks.len as the starting index because HTML chunks
            // may be interleaved with JS chunks, so js_chunks.count() would be
            // incorrect when HTML entry points are present.
            for (sorted_index, &key) in (sorted_chunks.len() as usize..).zip(sorted_css_keys.iter())
            {
                let index = css_chunks.get_index(&key).expect("unreachable");
                // PERF(port): was assume_capacity
                let owned = core::mem::take(&mut css_chunks.values_mut()[index]);
                sorted_chunks.append_assume_capacity(owned);
                remapped_css_indexes[index] = u32::try_from(sorted_index).expect("int cast");
            }

            // Update all affected JS chunks to point at the correct CSS chunk index.
            for &js_index in js_chunk_indices_with_css.slice() {
                if let chunk::Content::Javascript(js) =
                    &mut sorted_chunks.slice_mut()[js_index as usize].content
                {
                    for idx in js.css_chunks.iter_mut() {
                        *idx = remapped_css_indexes[*idx as usize];
                    }
                }
            }
        }

        // We don't care about the order of the HTML chunks that have no JS chunks.
        for v in html_chunks.values_mut() {
            sorted_chunks.push(core::mem::take(v));
        }

        break 'sort_chunks sorted_chunks;
        // TODO(port): return type — Zig returns []Chunk allocated by this.arena(); here we return Box<[Chunk]>.
        // Phase B: confirm ownership of `chunks` slice (sorted_chunks Vec backing storage).
    };
    let chunks: &mut [Chunk] = sorted_chunks.slice_mut();

    let entry_point_chunk_indices: &mut [u32] =
        this.graph.files.items_entry_point_chunk_index_mut();
    // Map from the entry point file to this chunk. We will need this later if
    // a file contains a dynamic import to this entry point, since we'll need
    // to look up the path for this chunk to use with the import.
    for (chunk_id, chunk) in chunks.iter_mut().enumerate() {
        if chunk.entry_point.is_entry_point() {
            // JS entry points that import CSS files generate two chunks, a JS chunk
            // and a CSS chunk. Don't link the CSS chunk to the JS file since the CSS
            // chunk is secondary (the JS chunk is primary).
            if matches!(chunk.content, chunk::Content::Css(_))
                && css_asts[chunk.entry_point.source_index() as usize].is_none()
            {
                continue;
            }
            entry_point_chunk_indices[chunk.entry_point.source_index() as usize] =
                u32::try_from(chunk_id).expect("int cast");
        }
    }

    // Determine the order of JS files (and parts) within the chunk ahead of time
    find_all_imported_parts_in_js_order(this, chunks)?;

    // Handle empty chunks case
    if chunks.is_empty() {
        this.unique_key_buf = Box::default();
        return Ok(Box::default());
    }

    let unique_key_item_len = chunk::UNIQUE_KEY_LEN;
    let mut unique_key_builder =
        bun_core::StringBuilder::init_capacity(unique_key_item_len * chunks.len());
    // PORT NOTE: in Zig `unique_key_buf` aliases the builder's backing buffer and
    // every `chunk.unique_key` is a slice into it. Mirror that: the builder never
    // reallocates after `init_capacity`, so each `fmt()` returns a stable subslice
    // that we detach to `&'static [u8]` (BACKREF) and transfer ownership of the
    // single allocation into `this.unique_key_buf` afterwards.
    let prefix_len = chunk::UNIQUE_KEY_PREFIX_LEN;

    // SAFETY: `this` points to LinkerContext which is the `linker` field of BundleV2.
    // Derived from `this_ptr` (raw) so it does not reborrow `*this` here — the column
    // slices below hold disjoint immutable borrows into `this.graph`.
    let bv2: &mut BundleV2 = unsafe { &mut *LinkerContext::bundle_v2_ptr(this_ptr) };
    let kinds = this.graph.files.items_entry_point_kind();
    let output_paths = this.graph.entry_points.items_output_path();
    // PORT NOTE: re-borrow after `find_all_imported_parts_in_js_order` released `&mut this`.
    let ast_targets = this.graph.ast.items_target();
    for (chunk_id, chunk) in chunks.iter_mut().enumerate() {
        // Assign a unique key to each chunk. This key encodes the index directly so
        // we can easily recover it later without needing to look it up in a map. The
        // last 8 numbers of the key are the chunk index.
        let written = unique_key_builder.fmt(format_args!(
            "{}",
            chunk::UniqueKey {
                prefix: unique_key,
                kind: chunk::QueryKind::Chunk,
                index: chunk_id as u32,
            },
        ));
        debug_assert_eq!(written.len(), chunk::UNIQUE_KEY_LEN);
        // SAFETY: `written` borrows the builder's fixed-capacity heap
        // allocation; ownership of that allocation is transferred to
        // `this.unique_key_buf` after this loop, which outlives every `Chunk` for
        // the link step (BACKREF — same as `final_rel_path`). On any `?` error
        // before the transfer, `sorted_chunks` is dropped alongside the builder,
        // so no dangling slice escapes.
        chunk.unique_key = unsafe { bun_ptr::detach_lifetime_ref::<[u8]>(written) };
        if this.unique_key_prefix.is_empty() {
            this.unique_key_prefix = chunk.unique_key[..prefix_len].into();
        }

        if chunk.entry_point.is_entry_point()
            && (matches!(chunk.content, chunk::Content::Html)
                || (kinds[chunk.entry_point.source_index() as usize]
                    == crate::EntryPoint::Kind::UserSpecified
                    && !chunk.flags.contains(chunk::Flags::HAS_HTML_CHUNK)))
        {
            // Use fileWithTarget template if there are HTML imports and user hasn't manually set naming
            if has_server_html_imports && bv2.transpiler().options.entry_naming.is_empty() {
                chunk.template = PathTemplate::FILE_WITH_TARGET.into();
            } else {
                chunk.template = PathTemplate::FILE.into();
                if chunk
                    .flags
                    .contains(chunk::Flags::IS_BROWSER_CHUNK_FROM_SERVER_BUILD)
                {
                    chunk.template.data = bv2
                        .transpiler_for_target(Target::Browser)
                        .options
                        .entry_naming
                        .clone();
                } else {
                    chunk.template.data = bv2.transpiler().options.entry_naming.clone();
                }
            }
        } else {
            if has_server_html_imports && bv2.transpiler().options.chunk_naming.is_empty() {
                chunk.template = PathTemplate::CHUNK_WITH_TARGET.into();
            } else {
                chunk.template = PathTemplate::CHUNK.into();
                if chunk
                    .flags
                    .contains(chunk::Flags::IS_BROWSER_CHUNK_FROM_SERVER_BUILD)
                {
                    chunk.template.data = bv2
                        .transpiler_for_target(Target::Browser)
                        .options
                        .chunk_naming
                        .clone();
                } else {
                    chunk.template.data = bv2.transpiler().options.chunk_naming.clone();
                }
            }
        }

        let pathname = bun_fs::PathName::init(
            output_paths[chunk.entry_point.entry_point_id() as usize].slice(),
        );
        chunk.template.placeholder.name = pathname.base.to_vec().into_boxed_slice();
        chunk.template.placeholder.ext = chunk.content.ext().to_vec().into_boxed_slice();

        if chunk.template.needs(PlaceholderField::Target) {
            // Determine the target from the AST of the entry point source
            let chunk_target = ast_targets[chunk.entry_point.source_index() as usize];
            chunk.template.placeholder.target = match chunk_target {
                Target::Browser => b"browser".to_vec().into_boxed_slice(),
                Target::Bun => b"bun".to_vec().into_boxed_slice(),
                Target::Node => b"node".to_vec().into_boxed_slice(),
                Target::BunMacro => b"macro".to_vec().into_boxed_slice(),
                Target::BakeServerComponentsSsr => b"ssr".to_vec().into_boxed_slice(),
            };
        }

        if chunk.template.needs(PlaceholderField::Dir) {
            // this if check is a specific fix for `bun build hi.ts --external '*'`, without leading `./`
            let dir_path: &[u8] = if !pathname.dir.is_empty() {
                pathname.dir
            } else {
                b"."
            };
            let mut real_path_buf = PathBuffer::uninit();
            let dir: &[u8] = 'dir: {
                let Ok(dir_file) = bun_sys::File::openat(
                    bun_sys::Fd::cwd(),
                    dir_path,
                    bun_sys::O::PATH | bun_sys::O::DIRECTORY,
                    0,
                ) else {
                    break 'dir &*resolve_path::normalize_buf::<bun_paths::platform::Auto>(
                        dir_path,
                        &mut real_path_buf.0,
                    );
                };
                let _close = bun_sys::CloseOnDrop::file(&dir_file);

                match dir_file.get_path(&mut real_path_buf) {
                    Ok(p) => break 'dir p,
                    Err(err) => {
                        // Split-borrow — see `LinkerContext::log_disjoint`.
                        this.log_disjoint().add_error_fmt(
                            None,
                            bun_ast::Loc::EMPTY,
                            format_args!(
                                "{}: Failed to get full path for directory '{}'",
                                bstr::BStr::new(err.name()),
                                bstr::BStr::new(dir_path)
                            ),
                        );
                        return Err(bun_core::err!("BuildFailed"));
                    }
                }
            };

            let root_dir = &this.resolver().opts.root_dir;
            chunk.template.placeholder.dir = resolve_path::relative_alloc(root_dir, dir)?;
        }
    }

    // Transfer ownership of the single backing buffer; every `chunk.unique_key`
    // above borrows into it. (Zig's `errdefer` freed the builder and cleared
    // `unique_key_buf`; in Rust the builder `Drop`s on error and `unique_key_buf`
    // is only assigned here on success, so no rollback guard is needed.)
    this.unique_key_buf = unique_key_builder.move_to_slice();

    Ok(sorted_chunks.to_owned_slice())
    // TODO(port): return type — Zig returns []Chunk allocated by this.arena(); here we return Box<[Chunk]>.
    // Phase B: confirm ownership of `chunks` slice (sorted_chunks Vec backing storage).
}

